import type { Platform } from 'frontend-platform_detection';
import type { MetricStoreName } from './types';

import { config } from 'frontend-config';
import { getPlatform } from '@nordic/core-context';

export function getConfigProps(
  storeName: MetricStoreName,
): Record<string, unknown> {
  const platform = getPlatform<Platform>();

  return (
    (platform
      ? config.get(storeName, platform.id, platform.siteId)
      : config[storeName]) ?? {}
  );
}
